from dataclasses import dataclass, field
from typing import Any
from enum import Enum

class EpisodeOutcome(Enum):
    SUCCESS  = 'success'
    FAILURE  = 'failure'
    PARTIAL  = 'partial'
    ABORTED  = 'aborted'

@dataclass
class EpisodeStep:
    index: int
    action: str            # tool or reasoning step
    result: Any            # what actually happened
    error: str = ''        # non-empty if this step failed

@dataclass
class Episode:
    goal: str
    steps: list[EpisodeStep]
    outcome: EpisodeOutcome
    final_output: str = ''
    lessons: list[str] = field(default_factory=list)  # filled by reflect()

    def failed_steps(self) -> list[EpisodeStep]:
        return [s for s in self.steps if s.error]

    def summary(self) -> str:
        lines = [
            f'Goal: {self.goal}',
            f'Outcome: {self.outcome.value}',
            f'Steps: {len(self.steps)} ({len(self.failed_steps())} failed)',
        ]
        if self.lessons:
            lines.append('Lessons: ' + '; '.join(self.lessons))
        return '\n'.join(lines)

from collections import deque

@dataclass
class EpisodicMemory:
    max_episodes: int = 10
    _episodes: deque = field(default_factory=lambda: deque(maxlen=10))

    def add(self, episode: Episode) -> None:
        if not episode.lessons:
            reflect_on_episode(episode)  # ensure lessons are extracted
        self._episodes.append(episode)

    def relevant_lessons(self, current_goal: str, max_lessons: int = 5) -> list[str]:
        """
        Return lessons from recent episodes, most recent first.
        A more sophisticated version could filter by goal similarity.
        """
        all_lessons = []
        for ep in reversed(self._episodes):
            all_lessons.extend(ep.lessons)
        return all_lessons[:max_lessons]

    def context_block(self, current_goal: str) -> str:
        lessons = self.relevant_lessons(current_goal)
        if not lessons:
            return ''
        lines = ['Lessons from previous runs:']
        lines.extend(f'- {l}' for l in lessons)
        return '\n'.join(lines)

memory = EpisodicMemory(max_episodes=10)

def run_episode_with_reflection(
    client,
    goal: str,
    run_agent_fn,    # (goal, context) -> (steps, outcome, output)
) -> Episode:
    context = memory.context_block(goal)
    steps, outcome, output = run_agent_fn(goal, context)
    ep = Episode(goal=goal, steps=steps, outcome=outcome, final_output=output)
    memory.add(ep)  # triggers reflect_on_episode
    return ep

def deduplicate_lessons(lessons: list[str], threshold: float = 0.8) -> list[str]:
    """
    Remove near-duplicate lessons using simple word-overlap similarity.
    Keeps the first occurrence of each near-duplicate cluster.
    """
    def similarity(a: str, b: str) -> float:
        wa = set(a.lower().split())
        wb = set(b.lower().split())
        if not wa or not wb:
            return 0.0
        return len(wa & wb) / len(wa | wb)  # Jaccard similarity

    unique: list[str] = []
    for lesson in lessons:
        if all(similarity(lesson, u) < threshold for u in unique):
            unique.append(lesson)
    return unique

@dataclass
class DeduplicatingMemory(EpisodicMemory):
    def relevant_lessons(self, current_goal: str, max_lessons: int = 5) -> list[str]:
        raw = super().relevant_lessons(current_goal, max_lessons=max_lessons * 2)
        return deduplicate_lessons(raw)[:max_lessons]

# Filter lessons by goal-type similarity to avoid cross-contamination.
# Uses simple keyword overlap — no embeddings required.

def goal_similarity(goal_a: str, goal_b: str) -> float:
    wa = set(goal_a.lower().split())
    wb = set(goal_b.lower().split())
    if not wa or not wb:
        return 0.0
    return len(wa & wb) / len(wa | wb)

class FilteredEpisodicMemory(EpisodicMemory):
    """Only include lessons from episodes with similar goals."""
    def relevant_lessons(
        self,
        current_goal: str,
        max_lessons: int = 5,
        similarity_threshold: float = 0.15,
    ) -> list[str]:
        lessons = []
        for ep in reversed(self._episodes):
            sim = goal_similarity(current_goal, ep.goal)
            if sim >= similarity_threshold:
                lessons.extend(ep.lessons)
        lessons = deduplicate_lessons(lessons)
        return lessons[:max_lessons]

# Comparing episode outcomes over time to detect improvement.

from collections import Counter

def outcome_summary(memory: EpisodicMemory) -> dict:
    counts = Counter(ep.outcome.value for ep in memory._episodes)
    total = len(memory._episodes)
    if total == 0:
        return {}
    return {
        outcome: {'count': n, 'rate': round(n / total, 2)}
        for outcome, n in counts.items()
    }

def average_steps(memory: EpisodicMemory) -> float:
    episodes = list(memory._episodes)
    if not episodes:
        return 0.0
    return sum(len(ep.steps) for ep in episodes) / len(episodes)

